function I(r,s,i){r=Math.max(1,r),s=Math.max(1,s),i=Math.max(2,i);const l=new Map,h=[],e=[];for(let t=0;t<r;t++){const a=`n${t}`;l.set(a,t),h.push({id:a,index:t,group:0,attrs:{}})}const n=new Uint8Array(r);for(let t=0;t<s;t++){const a=2+Math.floor(Math.random()*(i-1)),f=Math.min(a,r),c=new Set;for(;c.size<f;)c.add(Math.floor(Math.random()*r));const m=Array.from(c);for(const p of m)n[p]=1;e.push({id:t,index:t,memberIndices:m,attrs:{}})}s*i<r&&(i=Math.ceil(r/s));for(let t=0;t<r;t++)if(!n[t]){let a=Math.floor(Math.random()*s);for(let f=0;f<s;f++){const c=(a+f)%s;if(e[c].memberIndices.length<i){a=c;break}}e[a].memberIndices.push(t),n[t]=1}const o=new Int32Array(r).fill(-1);for(const t of e)for(const a of t.memberIndices)o[a]===-1&&(o[a]=t.index);for(let t=0;t<r;t++)h[t].group=o[t]>=0?o[t]%16:0;return{nodes:h,hyperedges:e,nodeIdToIndex:l}}export{I as generateRandomHypergraph};
